 {"actor":"mayor","comment":null,"created_at":"2026-03-01T19:07:52Z","event_type":"status_changed","id":2545,"issue_id":"bd-hwxg","new_value":"{\"assignee\":\"beads/polecats/jasper\",\"status\":\"hooked\"}","old_value":"{\"id\":\"bd-hwxg\",\"title\":\"remotes.go Fix field set to 'Remote Consistency' instead of actionable instructions\",\"description\":\"In remotes.go line ~110, when there are non-conflicting discrepancies, the Fix field is set to 'Remote Consistency' — a string that appears to be a leftover key from a refactor. As a user-facing message it is meaningless. The Fix field should contain instructions like 'Run bd doctor --fix to sync remotes'.\\n\\nSuggested fix: Replace with actual user-facing fix instructions.\",\"status\":\"open\",\"priority\":2,\"issue_type\":\"bug\",\"owner\":\"steve.yegge@gmail.com\",\"created_at\":\"2026-03-01T18:11:27Z\",\"created_by\":\"beads/polecats/jasper\",\"updated_at\":\"2026-03-01T18:11:27Z\"}"}
